/**
 * Provincial Suitability Indices for Weighted Overlay GIS
 * Auto-generated from BPS + portal data on 2026-05-03
 * 
 * 21 layers mapped to 38 provinces with normalized scores 0-100
 */

export interface SuitabilityIndices {
  province: string;
  // Spatial layers
  roadNetworkIndex: number;        // Proximity to toll roads (proxy)
  portDistanceIndex: number;       // Proximity to major ports
  airportDistanceIndex: number;     // Proximity to airports
  industrialZoneIndex: number;      // KI density / proximity
  landSuitabilityIndex: number;     // Composite land use score
  slopeIndex: number;              // Elevation/suitability
  floodRiskIndex: number;          // Inverse flood risk
  utilityIndex: number;            // Electricity/internet proxy
  // Socio-economic layers
  populationDensityIndex: number;   // Log-normalized
  workforceIndex: number;           // Workforce availability
  umrCompetitivenessIndex: number;  // Lower = higher score
  educationIndex: number;          // Education level proxy
  economicActivityIndex: number;   // PDRB / economic vibrancy
  // Regulatory (binary constraints)
  zoningCompliance: number;       // 1 = compliant, 0 = restricted
  protectedAreaConstraint: number;  // 1 = clear, 0 = protected
  forestConstraint: number;         // 1 = clear, 0 = forest
  miningConstraint: number;         // 1 = clear, 0 = overlap
  // PIR-specific
  investmentRealizationIndex: number;
  projectDensityIndex: number;      // Projects per area
  sectorSpecializationScore: number;
  commodityMatchScore: number;     // Varies by target sector
}

export const defaultWeights = {
  // Spatial (64%)
  roadNetworkIndex: 12,
  portDistanceIndex: 10,
  airportDistanceIndex: 8,
  industrialZoneIndex: 15,
  landSuitabilityIndex: 8,
  slopeIndex: 6,
  floodRiskIndex: 5,
  utilityIndex: 5,
  // Socio-economic (34%)
  populationDensityIndex: 8,
  workforceIndex: 8,
  umrCompetitivenessIndex: 5,
  educationIndex: 4,
  economicActivityIndex: 5,
  // PIR-specific (18%)
  investmentRealizationIndex: 5,
  projectDensityIndex: 4,
  sectorSpecializationScore: 4,
  commodityMatchScore: 4,
} as const;

// Sector-specific weight adjustments
