// Helper functions
export function getProvinceSuitability(province: string): SuitabilityIndices | undefined {
  return provincialSuitabilityIndices.find(p => p.province === province);
}

export function calculateWeightedScore(
  indices: SuitabilityIndices,
  weights: typeof defaultWeights = defaultWeights,
  sector?: string
): number {
  let w = { ...weights };

  // Apply sector overrides
  if (sector && sectorWeightOverrides[sector]) {
    w = { ...w, ...sectorWeightOverrides[sector] };
  }

  let score = 0;
  let totalWeight = 0;

  for (const [key, weight] of Object.entries(w)) {
    const value = indices[key as keyof SuitabilityIndices] as number;
    score += value * weight;
    totalWeight += weight;
  }

  // Apply constraint multiplier
  const constraintMultiplier = Math.min(
    indices.zoningCompliance,
    indices.protectedAreaConstraint,
    indices.forestConstraint,
    indices.miningConstraint
  );

  return Math.round((score / totalWeight) * constraintMultiplier);
}

export function rankProvincesForSector(
  sector: string,
  weights: Partial<typeof defaultWeights> = {}
): Array<{ province: string; score: number; rank: number }> {
  const w = { ...defaultWeights, ...weights };
  if (sectorWeightOverrides[sector]) {
    Object.assign(w, sectorWeightOverrides[sector]);
  }

  const scored = provincialSuitabilityIndices.map(p => ({
    province: p.province,
    score: calculateWeightedScore(p, w, sector),
  }));

  scored.sort((a, b) => b.score - a.score);

  return scored.map((s, i) => ({ ...s, rank: i + 1 }));
}

export function getTopProvincesForProject(
  targetSector: string,
  topN: number = 5
): Array<{ province: string; score: number; matchReasons: string[] }> {
  const ranked = rankProvincesForSector(targetSector);

  return ranked.slice(0, topN).map(r => {
    const idx = getProvinceSuitability(r.province)!;
    const reasons: string[] = [];

    if (idx.industrialZoneIndex >= 80) reasons.push("Established industrial zones");
    if (idx.portDistanceIndex >= 80) reasons.push("Coastal / near port");
    if (idx.workforceIndex >= 70) reasons.push("Large workforce pool");
    if (idx.umrCompetitivenessIndex >= 70) reasons.push("Competitive labor cost");
    if (idx.commodityMatchScore >= 60) reasons.push("Raw material availability");
    if (idx.investmentRealizationIndex >= 70) reasons.push("Proven investment track record");
    if (idx.sectorSpecializationScore >= 60) reasons.push("Sector ecosystem present");
    if (idx.roadNetworkIndex >= 80) reasons.push("Good road connectivity");

    return { ...r, matchReasons: reasons };
  });
}
